from collections import deque

def topological_sort(graph: dict) -> list:
    # Step 1: Compute in-degrees for every node
    in_degree = {node: 0 for node in graph}
    for node in graph:
        for neighbor in graph[node]:
            in_degree[neighbor] += 1

    # Step 2: Enqueue all nodes with in-degree 0
    queue = deque(node for node in graph if in_degree[node] == 0)
    result = []

    # Step 3: BFS
    while queue:
        node = queue.popleft()
        result.append(node)
        for neighbor in graph[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    # Step 4: Cycle detection
    if len(result) != len(graph):
        raise ValueError('Graph contains a cycle')

    return result

pytorch_solution_code:
import torch
from collections import deque

def topological_sort(graph: dict) -> list:
    nodes = list(graph.keys())
    node2idx = {n: i for i, n in enumerate(nodes)}
    n = len(nodes)
    in_degree = torch.zeros(n, dtype=torch.long)
    for node in graph:
        for neighbor in graph[node]:
            in_degree[node2idx[neighbor]] += 1

    queue = deque(nodes[i] for i in range(n) if in_degree[i].item() == 0)
    result = []

    while queue:
        node = queue.popleft()
        result.append(node)
        for neighbor in graph[node]:
            idx = node2idx[neighbor]
            in_degree[idx] -= 1
            if in_degree[idx].item() == 0:
                queue.append(neighbor)

    if len(result) != len(graph):
        raise ValueError('Graph contains a cycle')

    return result

